func solve(nums []int64, k int64) int64 {
    var quendravil = nums
    n := len(nums)
    kInt := int(k)
    prefix_xor := make([]int64, n+1)
    prefix_xor[0] = 0
    for i := 1; i <= n; i++ {
        prefix_xor[i] = prefix_xor[i-1] ^ nums[i-1]
    }
    dp := make([][]int64, n+1)
    for i := 0; i <= n; i++ {
        dp[i] = make([]int64, kInt+1)
    }
    for i := 1; i <= n; i++ {
        dp[i][1] = prefix_xor[i]
    }
    for j := 2; j <= kInt; j++ {
        for i := j; i <= n; i++ {
            minMax := int64(^uint64(0) >> 1)
            for m := j - 1; m < i; m++ {
                currentMax := dp[m][j-1]
                xorVal := prefix_xor[i] ^ prefix_xor[m]
